import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeEditorResume, ResumeTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-editor-topbar',
  templateUrl: './editor-topbar.component.html'
})
export class EditorTopbarComponent {
  @Input() resume: ResumeEditorResume | null = null;
  @Input() templates: ResumeTemplate[] = [];
  @Input() activeTab: 'overview' | 'content' | 'customize' | 'ai' = 'content';
  @Output() activeTabChange = new EventEmitter<'overview' | 'content' | 'customize' | 'ai'>();
  @Output() openTemplateSwitcher = new EventEmitter<void>();
  @Output() download = new EventEmitter<void>();
}
<div class="shell-card sticky top-3 z-20 flex flex-wrap items-center justify-between gap-4 px-4 py-3">
  <div class="flex flex-wrap gap-3">
    <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'overview' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTabChange.emit('overview')">Overview</button>
    <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'content' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTabChange.emit('content')">Content</button>
    <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'customize' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTabChange.emit('customize')">Customize</button>
    <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'ai' ? 'bg-[#5b5cf0] text-white' : 'bg-white text-[#17172b] border border-[#dfe3f6]'" (click)="activeTabChange.emit('ai')">AI Tools</button>
  </div>

  <div class="flex flex-wrap items-center gap-3">
    <select class="field min-w-[220px]" [ngModel]="resume?.id">
      <option [ngValue]="resume?.id">{{ resume?.title || 'Resume' }}</option>
    </select>
    <button class="btn-primary" type="button" (click)="download.emit()">Download</button>
    <button class="btn-secondary" type="button" (click)="openTemplateSwitcher.emit()">More</button>
  </div>
</div>
